// Formater la configuration globale
const response = $input.item.json.result || $input.item.json;
const config = response.data || response.config || response;

if (!config || typeof config !== 'object') {
  return {
    json: {
      success: false,
      message: "❌ Impossible de récupérer la configuration globale.",
      config: null
    }
  };
}

let formattedText = '**Configuration Globale BunkerWeb:**\n\n';

// Grouper les variables par catégorie
const categories = {
  'Sécurité': ['USE_MODSECURITY', 'USE_MODSECURITY_CRS', 'USE_ANTIBOT', 'USE_BAD_BEHAVIOR'],
  'Limites': ['USE_LIMIT_REQ', 'LIMIT_REQ_RATE', 'LIMIT_REQ_BURST'],
  'SSL/TLS': ['AUTO_LETS_ENCRYPT', 'USE_CUSTOM_SSL', 'HTTPS_PROTOCOLS'],
  'Logs': ['LOG_LEVEL', 'MODSECURITY_SEC_AUDIT_LOG']
};

Object.entries(categories).forEach(([category, vars]) => {
  const categoryVars = vars.filter(v => config[v] !== undefined && config[v] !== null && config[v] !== '');
  if (categoryVars.length > 0) {
    formattedText += `**${category}:**\n`;
    categoryVars.forEach(varName => {
      formattedText += `• ${varName}: ${config[varName]}\n`;
    });
    formattedText += '\n';
  }
});

// Compter les autres variables
const allCategoryVars = Object.values(categories).flat();
const otherVars = Object.keys(config).filter(k => 
  !allCategoryVars.includes(k) && config[k] !== null && config[k] !== ''
);

if (otherVars.length > 0) {
  formattedText += `(+ ${otherVars.length} autre(s) variable(s) configurée(s))\n`;
}

return {
  json: {
    success: true,
    message: formattedText,
    config: config,
    total_vars: Object.keys(config).length
  }
};
